import{_ as e,o as l,c as a,a2 as o}from"./chunks/framework.Pywvta2k.js";const u=JSON.parse('{"title":"李辛","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/05-近现代/05-李辛.md","filePath":"tcm-data/05-近现代/05-李辛.md","lastUpdated":1781084559000}'),r={name:"tcm-data/05-近现代/05-李辛.md"};function n(s,t,i,d,g,h){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="李辛" tabindex="-1">李辛 <a class="header-anchor" href="#李辛" aria-label="Permalink to &quot;李辛&quot;">​</a></h1><blockquote><p>李辛（1960年生），北京人 当代中医身心医学的代表人物 代表作：《经典中医启蒙》《儿童健康讲记》《精神健康讲记》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>经历</strong>：北京中医药大学毕业，执业中医师</li><li><strong>师承</strong>：宋祚民（儿科名家）</li><li><strong>教学</strong>：瑞士、法国、德国等多国中医教学经验</li><li><strong>学术特色</strong>：以**能量（气）**的视角解读中医，融合现代身心医学</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-能量模型-三焦能量论" tabindex="-1">1. 能量模型（三焦能量论） <a class="header-anchor" href="#_1-能量模型-三焦能量论" aria-label="Permalink to &quot;1. 能量模型（三焦能量论）&quot;">​</a></h3><p>李辛以**能量（气）的&quot;开阖&quot;**为核心来理解人体：</p><table tabindex="0"><thead><tr><th style="text-align:left;">层次</th><th style="text-align:left;">对应</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>上焦</strong>（心、肺）</td><td style="text-align:left;">能量的宣发</td><td style="text-align:left;">开——向外、向上</td></tr><tr><td style="text-align:left;"><strong>中焦</strong>（脾、胃）</td><td style="text-align:left;">能量的来源</td><td style="text-align:left;">枢纽——能量的化生</td></tr><tr><td style="text-align:left;"><strong>下焦</strong>（肝、肾）</td><td style="text-align:left;">能量的储存</td><td style="text-align:left;">阖——向内、向下、封藏</td></tr></tbody></table><p><strong>诊断思路</strong>：</p><ul><li>上焦开得太厉害（前胸出汗多）→ 相火不降</li><li>中焦来源不足（胃口差、腹胀）→ 能量不够</li><li>下焦封藏不住（腰凉、脚冷、月经提前）→ 肾不藏精</li></ul><h3 id="_2-开阖理论" tabindex="-1">2. 开阖理论 <a class="header-anchor" href="#_2-开阖理论" aria-label="Permalink to &quot;2. 开阖理论&quot;">​</a></h3><blockquote><p><strong>「人体的能量，如一朵花。该开时开，该阖时阖。」</strong></p></blockquote><ul><li><strong>开</strong>：对外界的接触（出汗、说话、社交、运动）</li><li><strong>阖</strong>：对内的收敛（休息、睡眠、安静、独处）</li><li><strong>健康 = 开阖有度</strong></li><li><strong>疾病 = 开阖失序</strong></li></ul><p><strong>普光</strong>：前胸出汗多（开太过） + 运动时尤甚 → 上焦开得太厉害，需要潜降 <strong>普明</strong>：傍晚疲惫（阖不了）+ 入睡困难 → 能量不够，且该阖时阖不住</p><h3 id="_3-能量与信息" tabindex="-1">3. 能量与信息 <a class="header-anchor" href="#_3-能量与信息" aria-label="Permalink to &quot;3. 能量与信息&quot;">​</a></h3><blockquote><p><strong>「人体是一个能量体，也是一套信息接收系统。」</strong></p></blockquote><ul><li>环境的能量会直接影响人体（如大理苍山的湿气）</li><li>情绪是一种能量信息（烦躁是肝的信息郁结）</li><li>治疗 = 调整能量的开阖</li></ul><h3 id="_4-三焦虚实判断法-极其实用" tabindex="-1">4. 三焦虚实判断法（极其实用） <a class="header-anchor" href="#_4-三焦虚实判断法-极其实用" aria-label="Permalink to &quot;4. 三焦虚实判断法（极其实用）&quot;">​</a></h3><p>李辛的简化诊断法（不需要复杂辨证）：</p><p><strong>看三焦的虚实：</strong></p><ol><li><strong>下焦虚</strong>：腰酸、腿软、脚跟裂、月经提前、胆小</li><li><strong>中焦虚</strong>：腹胀、饭后困、大便不通或稀、肌肉松软</li><li><strong>上焦虚</strong>：怕风、容易感冒、气短、面色白</li></ol><p><strong>看能量的开阖：</strong></p><ol><li><strong>开太过</strong>：出汗多、话多、社交多、停不下来</li><li><strong>阖太过</strong>：怕冷、不出汗、自闭、不动</li><li><strong>开阖失序</strong>：白天没精神、晚上睡不着</li></ol><h3 id="_5-病机层次" tabindex="-1">5. 病机层次 <a class="header-anchor" href="#_5-病机层次" aria-label="Permalink to &quot;5. 病机层次&quot;">​</a></h3><p>李辛认为，<strong>病有三个层次</strong>，治疗必须分清：</p><table tabindex="0"><thead><tr><th style="text-align:left;">层次</th><th style="text-align:left;">特点</th><th style="text-align:left;">治法</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>表</strong></td><td style="text-align:left;">病在皮肤、肌肉、经络</td><td style="text-align:left;">针灸、拔罐、运动</td></tr><tr><td style="text-align:left;"><strong>里</strong></td><td style="text-align:left;">病在脏腑</td><td style="text-align:left;">中药、饮食</td></tr><tr><td style="text-align:left;"><strong>神</strong></td><td style="text-align:left;">病在精神、意识、情绪</td><td style="text-align:left;">静坐、导引、心理调整</td></tr></tbody></table><hr><h2 id="三、经典名言精选" tabindex="-1">三、经典名言精选 <a class="header-anchor" href="#三、经典名言精选" aria-label="Permalink to &quot;三、经典名言精选&quot;">​</a></h2><h3 id="论能量" tabindex="-1">论能量 <a class="header-anchor" href="#论能量" aria-label="Permalink to &quot;论能量&quot;">​</a></h3><blockquote><p><strong>「人体是一个能量体。能量的开阖，就是生命的节奏。」</strong></p></blockquote><blockquote><p><strong>「健康的人，能量的开阖是自由的；不健康的人，能量被卡住了。」</strong></p></blockquote><blockquote><p><strong>「三焦的能量，上焦如雾，中焦如沤，下焦如渎。」</strong></p></blockquote><h3 id="论诊断" tabindex="-1">论诊断 <a class="header-anchor" href="#论诊断" aria-label="Permalink to &quot;论诊断&quot;">​</a></h3><blockquote><p><strong>「中医的诊断，不是找病名，而是看能量。」</strong></p></blockquote><blockquote><p><strong>「看一个病人，先看三焦的虚实，再看能量的开阖。」</strong></p></blockquote><blockquote><p><strong>「有能量的人，病在表；没能量的人，病在里。」</strong></p></blockquote><h3 id="论治疗" tabindex="-1">论治疗 <a class="header-anchor" href="#论治疗" aria-label="Permalink to &quot;论治疗&quot;">​</a></h3><blockquote><p><strong>「治病不是消灭症状，而是恢复人体的能量状态。」</strong></p></blockquote><blockquote><p><strong>「最好的治疗，是让人体的自愈能力恢复正常。」</strong></p></blockquote><blockquote><p><strong>「有时候，不做治疗就是最好的治疗——给身体一个修复的机会。」</strong></p></blockquote><h3 id="论生活" tabindex="-1">论生活 <a class="header-anchor" href="#论生活" aria-label="Permalink to &quot;论生活&quot;">​</a></h3><blockquote><p><strong>「现代人的病，大多数是能量不够+开阖失序。」</strong></p></blockquote><blockquote><p><strong>「休息是最好的补药。睡觉是最大的阖。」</strong></p></blockquote><blockquote><p><strong>「知道自己需要什么，比知道病名更重要。」</strong></p></blockquote><blockquote><p><strong>「健康的生活方式，就是符合自然节奏的生活方式。」</strong></p></blockquote><h3 id="论儿童" tabindex="-1">论儿童 <a class="header-anchor" href="#论儿童" aria-label="Permalink to &quot;论儿童&quot;">​</a></h3><blockquote><p><strong>「儿童的健康，不在于吃什么药，而在于吃什么饭、睡什么觉。」</strong></p></blockquote><blockquote><p><strong>「孩子的病，一半是吃出来的，一半是父母的焦虑给的。」</strong></p></blockquote><hr><h2 id="四、对普光-普明的直接指导" tabindex="-1">四、对普光/普明的直接指导 <a class="header-anchor" href="#四、对普光-普明的直接指导" aria-label="Permalink to &quot;四、对普光/普明的直接指导&quot;">​</a></h2><h3 id="普光-李辛视角" tabindex="-1">普光（李辛视角） <a class="header-anchor" href="#普光-李辛视角" aria-label="Permalink to &quot;普光（李辛视角）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">能量解读</th><th style="text-align:left;">对策</th></tr></thead><tbody><tr><td style="text-align:left;">前胸出汗多</td><td style="text-align:left;">上焦开太过</td><td style="text-align:left;">潜降药（龙牡）+ 减少大汗运动</td></tr><tr><td style="text-align:left;">腰腹凉</td><td style="text-align:left;">下焦能量不足</td><td style="text-align:left;">附子温肾 + 艾绒护腰</td></tr><tr><td style="text-align:left;">阴囊湿</td><td style="text-align:left;">中下焦湿浊不化</td><td style="text-align:left;">茯苓泽泻利湿</td></tr><tr><td style="text-align:left;">口渴不贪凉</td><td style="text-align:left;">能量不够，无力蒸腾津液</td><td style="text-align:left;">温阳潜降，不是滋阴</td></tr></tbody></table><h3 id="普明-李辛视角" tabindex="-1">普明（李辛视角） <a class="header-anchor" href="#普明-李辛视角" aria-label="Permalink to &quot;普明（李辛视角）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">能量解读</th><th style="text-align:left;">对策</th></tr></thead><tbody><tr><td style="text-align:left;">傍晚疲惫</td><td style="text-align:left;">能量不够+该阖时阖不住</td><td style="text-align:left;">早休息，少耗神</td></tr><tr><td style="text-align:left;">月经提前</td><td style="text-align:left;">下焦封藏不住</td><td style="text-align:left;">补肾固摄</td></tr><tr><td style="text-align:left;">烦躁</td><td style="text-align:left;">能量浮越在外</td><td style="text-align:left;">降相火</td></tr><tr><td style="text-align:left;">素食</td><td style="text-align:left;">能量来源不足（精微物质）</td><td style="text-align:left;">加强蛋奶，或考虑是否恢复适量肉食</td></tr></tbody></table><hr><h2 id="五、学习建议" tabindex="-1">五、学习建议 <a class="header-anchor" href="#五、学习建议" aria-label="Permalink to &quot;五、学习建议&quot;">​</a></h2><ol><li><strong>入门</strong>：《经典中医启蒙》——最好懂的中医入门书</li><li><strong>进阶</strong>：《儿童健康讲记》——即使没有孩子，也能理解能量模型</li><li><strong>深入</strong>：《精神健康讲记》——身心一体的能量观</li></ol><hr><p><em>本条目为精简框架版。李辛的能量模型可发展为独立的诊断框架，与黄元御的&quot;一气周流&quot;模型互补使用。</em></p>',61)])])}const c=e(r,[["render",n]]);export{u as __pageData,c as default};
